import React, { useState, useEffect } from "react";
import axios from "axios";

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

const SendEmailPage = () => {
  const [subject, setSubject] = useState("");
  const [group, setGroup] = useState("all");
  const [templateName, setTemplateName] = useState("promo");
  const [htmlContent, setHtmlContent] = useState("");
  const [resultMsg, setResultMsg] = useState(null);
  const [recipientEmails, setRecipientEmails] = useState([]);
  const [showEmailPopup, setShowEmailPopup] = useState(false);


  // 📌 Mẫu email
  const templates = {
    promo: `
      <h2>🎉 Ưu đãi đặc biệt!</h2>
      <p>Giảm 20% cho tất cả sản phẩm trong tuần này!</p>
    `,
    holiday: `
      <h2>🌸 Quà tặng ngày lễ!</h2>
      <p>Ưu đãi dành riêng cho các dịp lễ hội.</p>
    `,
    custom: "",
  };

  // Khi đổi template
  useEffect(() => {
    if (templateName !== "custom") {
      setHtmlContent(templates[templateName]);
    }
  }, [templateName]);

  // =====================================
  //       📩 GỬI EMAIL MARKETING
  // =====================================
  const sendEmail = async () => {
    setResultMsg(null);

    // Lấy token đúng chuẩn
    const storedUser = JSON.parse(localStorage.getItem("userInfo"));
    const token = storedUser?.token;

    if (!token) {
      setResultMsg({
        type: "error",
        text: "❌ Bạn chưa đăng nhập (không có token).",
      });
      return;
    }

    try {
      const res = await axios.post(
        `${API_URL}/api/email/send`,
        {
          subject,
          group,
          html: htmlContent,
          templateName,
        },
        {
          headers: { Authorization: `Bearer ${token}` },
        }
      );

      setResultMsg({ type: "success", text: res.data.message });
    } catch (err) {
      console.log("Email send error:", err);
      setResultMsg({
        type: "error",
        text: "❌ Không thể gửi email. Vui lòng kiểm tra backend!",
      });
    }
  };

  // =====================================
  //               ⛩️ UI
  // =====================================
  return (
    <div style={{ padding: "40px" }}>
      <h1
        style={{
          fontSize: "26px",
          fontWeight: "700",
          color: "#d14b6a",
          marginBottom: "20px",
        }}
      >
        📩 Gửi Email Marketing
      </h1>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: "40px",
          marginTop: "30px",
        }}
      >
        {/* FORM TRÁI */}
        <div
          style={{
            background: "white",
            padding: "25px",
            borderRadius: "12px",
            boxShadow: "0 10px 40px rgba(0,0,0,0.05)",
          }}
        >
          {/* Tiêu đề email */}
          <label>Tiêu đề Email</label>
          <input
            type="text"
            value={subject}
            onChange={(e) => setSubject(e.target.value)}
            placeholder="Nhập tiêu đề email…"
            style={{
              width: "100%",
              marginTop: "8px",
              marginBottom: "20px",
              padding: "12px",
              borderRadius: "8px",
              border: "1px solid #f1e4da",
            }}
          />

          {/* Nhóm nhận */}
          <label>Gửi đến nhóm</label>
          <select
            value={group}
            onChange={(e) => setGroup(e.target.value)}
            style={{
              width: "100%",
              padding: "12px",
              marginBottom: "20px",
              border: "1px solid #f1e4da",
              borderRadius: "8px",
            }}
          >
            <option value="all">📢 Tất cả khách hàng</option>
            <option value="user">👤 Người dùng</option>
            <option value="admin">🛠 Quản trị viên</option>
            <option value="newsletter">📬 Đăng ký nhận tin</option>
            <option value="vip">💎 Khách VIP</option>
          </select>

          {/* Mẫu email */}
          <label>Mẫu email</label>
          <select
            value={templateName}
            onChange={(e) => setTemplateName(e.target.value)}
            style={{
              width: "100%",
              padding: "12px",
              marginBottom: "20px",
              border: "1px solid #f1e4da",
              borderRadius: "8px",
            }}
          >
            <option value="promo">🎁 Khuyến mãi</option>
            <option value="holiday">🎉 Ngày lễ</option>
            <option value="custom">📝 Tùy chỉnh</option>
          </select>

          {/* Nếu chọn tùy chỉnh */}
          {templateName === "custom" && (
            <textarea
              rows="6"
              value={htmlContent}
              onChange={(e) => setHtmlContent(e.target.value)}
              placeholder="Nhập nội dung HTML…"
              style={{
                width: "100%",
                padding: "12px",
                marginBottom: "20px",
                borderRadius: "8px",
                border: "1px solid #f1e4da",
              }}
            />
          )}

          <button
            onClick={sendEmail}
            style={{
              width: "100%",
              background: "#d86b7a",
              padding: "15px",
              borderRadius: "8px",
              color: "white",
              fontWeight: "bold",
              cursor: "pointer",
              fontSize: "16px",
              transition: "0.3s",
            }}
          >
            ✉ Gửi Email
          </button>

          {/* THÔNG BÁO */}
          {resultMsg && (
            <div
              style={{
                marginTop: "20px",
                padding: "15px",
                borderRadius: "8px",
                background:
                  resultMsg.type === "success" ? "#e8fff0" : "#ffe8e8",
                color: resultMsg.type === "success" ? "#008f3c" : "#d10000",
                border:
                  resultMsg.type === "success"
                    ? "1px solid #b2ffcf"
                    : "1px solid #ffb3b3",
              }}
            >
              {resultMsg.text}
            </div>
          )}
        </div>

        {/* PREVIEW PHẢI */}
        <div
          style={{
            background: "#faf7f7",
            padding: "25px",
            borderRadius: "12px",
            border: "1px solid #f1e4da",
          }}
        >
          <h2 style={{ color: "#8b5e3c" }}>🔍 Xem trước nội dung</h2>

          <div
            style={{
              marginTop: "20px",
              background: "white",
              padding: "20px",
              borderRadius: "10px",
              border: "1px solid #ddd",
            }}
            dangerouslySetInnerHTML={{ __html: htmlContent }}
          />
        </div>
      </div>
    </div>
  );
};

export default SendEmailPage;
